const body = $input.first().json.body || $input.first().json;
if (body.event !== 'messages.upsert') return [];
const message = body.data;
if (!message) return [];
if (message.key?.fromMe === true) return [];
const text = message.message?.conversation || message.message?.extendedTextMessage?.text || '';
if (!text.trim()) return [];
const remoteJid = message.key.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '');
if (remoteJid.includes('@g.us')) return [];
return [{ json: { phone, text: text.trim(), pushName: message.pushName || '', remoteJid, messageId: message.key.id, timestamp: new Date().toISOString() } }];

const memoryResponse = $input.first().json;
const userData = $('Filtrar e Extrair Dados').first().json;
const memory = memoryResponse.memory || { messages: [], stage: 'greeting', leadData: {}, name: '' };
const recentMessages = (memory.messages || []).slice(-15);
const formattedHistory = recentMessages.map(m => `${m.role === 'user' ? 'Usuario' : 'Assistente'}: ${m.content}`).join('\n');
const userName = memory.name || userData.pushName || '';
return [{ json: { phone: userData.phone, text: userData.text, pushName: userData.pushName, remoteJid: userData.remoteJid, timestamp: userData.timestamp, history: formattedHistory, stage: memory.stage || 'greeting', leadData: memory.leadData || {}, userName, messageCount: recentMessages.length, previousMessages: recentMessages } }];

const input = $input.first().json;
const prevData = $('Preparar Contexto').first().json;
let aiResponse;
try {
  let text = input.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResponse = JSON.parse(text);
} catch (e) {
  const rawText = input.candidates?.[0]?.content?.parts?.[0]?.text || '';
  aiResponse = { intent: 'CONVERSA_GERAL', response: rawText || 'Desculpe, tive um probleminha. Pode repetir? 😊', stage: prevData.stage || 'greeting', leadData: {} };
}
const mergedLeadData = { ...prevData.leadData, ...(aiResponse.leadData || {}) };
Object.keys(mergedLeadData).forEach(key => { if (!mergedLeadData[key] || mergedLeadData[key] === 'null' || mergedLeadData[key] === 'undefined') delete mergedLeadData[key]; });
return [{ json: { phone: prevData.phone, remoteJid: prevData.remoteJid, text: prevData.text, pushName: prevData.pushName, timestamp: prevData.timestamp, userName: prevData.userName, previousMessages: prevData.previousMessages, intent: aiResponse.intent || 'CONVERSA_GERAL', response: aiResponse.response || 'Como posso te ajudar? 😊', courseQuery: aiResponse.courseQuery || '', leadData: mergedLeadData, stage: aiResponse.stage || prevData.stage || 'greeting' } }];

const coursesResponse = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
const courses = coursesResponse.courses || [];
let finalResponse = prevData.response;
if (courses.length > 0) {
  const list = courses.map((c, i) => {
    const tipo = c.type === 'BACHARELADO' ? 'Bacharelado' : c.type === 'LICENCIATURA' ? 'Licenciatura' : 'Tecnologo';
    const nivel = c.nivel === 'GRADUACAO' ? 'Graduacao' : 'Pos-Graduacao';
    const demanda = c.marketDemand === 'ALTA' ? '🟢 Alta' : c.marketDemand === 'MEDIA' ? '🟡 Media' : '🔴 Baixa';
    return `*${i + 1}. ${c.fullName || c.name}*\n   📚 ${tipo} | ${nivel}\n   ⏱ Duracao: ${c.duration || 'Consultar'}\n   💼 Demanda: ${demanda}\n   🔗 https://www.bolsaclick.com.br/cursos/${c.slug}`;
  }).join('\n\n');
  finalResponse = finalResponse + '\n\n' + list + '\n\n💡 Quer saber os valores com bolsa? Me diga qual te interessa!';
} else if (prevData.courseQuery) {
  finalResponse = finalResponse + '\n\nNao encontrei cursos com esse nome. Tente de outra forma ou me diga a area de interesse! 😊';
}
return [{ json: { ...prevData, response: finalResponse } }];

