const input = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
let academicInfo = '';
try { academicInfo = input.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch (e) { academicInfo = ''; }
let finalResponse = prevData.response;
if (academicInfo) { finalResponse = academicInfo + '\n\n💰 Quer saber os valores com bolsa no Bolsa Click?'; }
return [{ json: { ...prevData, response: finalResponse } }];

const leadResult = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
let finalResponse = prevData.response;
if (leadResult.lead?.id) { prevData.leadData.leadId = leadResult.lead.id; }
return [{ json: { ...prevData, response: finalResponse } }];

const prevData = $('Parsear Resposta Gemini').first().json;
let response = prevData.response;
if (prevData.intent === 'CHECKOUT' && prevData.leadData?.courseInterest) {
  const slug = prevData.leadData.courseInterest.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  if (!response.includes('bolsaclick.com.br')) { response += '\n\n👉 https://www.bolsaclick.com.br/cursos/' + slug; }
}
return [{ json: { ...prevData, response } }];

const data = $input.first().json;
let response = (data.response || 'Como posso te ajudar? 😊').substring(0, 4000);
return [{ json: { phone: data.phone, remoteJid: data.remoteJid, text: data.text, pushName: data.pushName, userName: data.userName, timestamp: data.timestamp, previousMessages: data.previousMessages || [], response, intent: data.intent, stage: data.stage, leadData: data.leadData || {} } }];

const data = $('Preparar Mensagem Final').first().json;
const previousMessages = data.previousMessages || [];
previousMessages.push({ role: 'user', content: data.text, timestamp: data.timestamp });
previousMessages.push({ role: 'assistant', content: data.response, timestamp: new Date().toISOString() });
const trimmedMessages = previousMessages.slice(-30);
return [{ json: { phone: data.phone, data: { name: data.userName || data.pushName || '', messages: trimmedMessages, stage: data.stage, leadData: data.leadData, lastInteraction: new Date().toISOString() } } }];
